const src = $json;

function toText(value) {
  if (value == null) return "";
  if (typeof value === "string") return value;
  if (Array.isArray(value)) return value.map((v) => toText(v)).join("\n");
  return String(value);
}

const mensagens = toText(
  src.mensagens ||
  src.messages ||
  src.conversa ||
  src.message?.text ||
  src.body ||
  ""
).replace(/\s+/g, " ").trim();

return [{
  json: {
    ticket_id: src.ticket_id || src.ticket?.id || src.conversation_id || `WT-${Date.now()}`,
    cliente: src.cliente || src.contact?.name || src.contact?.phoneNumber || src.customer?.name || "Cliente sem nome",
    canal: src.canal || src.channel || (src.contact?.phoneNumber ? "whatsapp" : "telefone"),
    tecnico: src.tecnico || src.ticket?.assignee?.name || "",
    data_evento: src.data_evento || src.timestamp || new Date().toISOString(),
    mensagens: mensagens || "[sem mensagens relevantes]"
  }
}];
